#define THREADS 256
#define WIDTH 16  
#define HEIGHT 16 
#define ETA 0.3f       
#define MOMENTUM 0.3f  

#ifndef _BACKPROP_CUDA_KERNEL_H_
#define _BACKPROP_CUDA_KERNEL_H_
#define WM(i, j)   weight_matrix[(j) + (i) * WIDTH]

#include <omp.h>

void 
bpnn_layerforward_omp(float *input_cuda,
	                  float *output_hidden_cuda,
					  float *input_hidden_cuda,
					  float *hidden_partial_sum,
					  int in,
					  int hid) 
{
	int num_blocks = in / HEIGHT; // assuming in divisible by HEIGHT (16)

	// Parallelize over by (block index)
	#pragma omp parallel for collapse(2)
	for (int by = 0; by < num_blocks; by++) {
		for (int tx = 0; tx < WIDTH; tx++) {
			float input_node[HEIGHT];
			float weight_matrix[HEIGHT * WIDTH];

			// Load input_node array (tx == 0 equivalent)
			for (int ty = 0; ty < HEIGHT; ty++) {
				int index_in = HEIGHT * by + ty + 1;
				input_node[ty] = input_cuda[index_in];
			}

			// Load weight_matrix from input_hidden_cuda
			for (int ty = 0; ty < HEIGHT; ty++) {
				int index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 ) ;
				weight_matrix[ty * WIDTH + tx] = input_hidden_cuda[index];
			}

			// Multiply weight_matrix elements by input_node
			for (int ty = 0; ty < HEIGHT; ty++) {
				weight_matrix[ty * WIDTH + tx] *= input_node[ty];
			}

			// Reduction loop (note: original code does parallel reduction with barriers)
			// We'll do iterative reductions in serial since within thread.
			for (int i = 1; i <= HEIGHT; i = i * 2) {
				int power_two = i;
				for (int ty = 0; ty < HEIGHT; ty += power_two) {
					if (ty + power_two/2 < HEIGHT) {
						weight_matrix[ty * WIDTH + tx] += weight_matrix[(ty + power_two/2) * WIDTH + tx];
					}
				}
			}

			// Write back to input_hidden_cuda
			for (int ty = 0; ty < HEIGHT; ty++) {
				int index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 ) ;
				input_hidden_cuda[index] = weight_matrix[ty * WIDTH + tx];
			}

			// Write partial sum output for tx == 0
			if (tx == 0) {
				for (int ty = 0; ty < HEIGHT; ty++) {
					hidden_partial_sum[by * hid + ty] = weight_matrix[ty];
				}
			}
		}
	}
}


void bpnn_adjust_weights_omp(float * delta,   
									 int hid,         
									float * ly,      
									 int in,          
									float * w,       
									float * oldw)  									
{
	int num_blocks = in / HEIGHT; // assuming in divisible by HEIGHT (16)

	#pragma omp parallel for collapse(2)
	for (int by = 0; by < num_blocks; by++) {
		for (int ty = 0; ty < HEIGHT; ty++) {
			for (int tx = 0; tx < WIDTH; tx++) {
				int index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 ) ;  
				int index_y = HEIGHT * by + ty + 1;
				int index_x = tx + 1;

				float new_dw = ((ETA * delta[index_x] * ly[index_y]) + (MOMENTUM * oldw[index]));
				w[index] += new_dw;
				oldw[index] = new_dw;
			}
		}
	}

	// Handle special case for ty == 0 && by == 0
	#pragma omp parallel for
	for (int tx = 0; tx < WIDTH; tx++) {
		int ty = 0;
		int by = 0;
		int index_x = tx + 1;
		w[index_x] += ((ETA * delta[index_x]) + (MOMENTUM * oldw[index_x]));
		oldw[index_x] = ((ETA * delta[index_x]) + (MOMENTUM * oldw[index_x]));
	}
}

#endif
